/**
 * Luxival Fare Calculator Widget
 * Reads pre-computed fares from /assets/data/fares.json (generated by Python).
 * Usage: include this script + call initFareCalculator({ preselect: ['airport'] })
 */

(function () {
  const SURCHARGE_LABELS = {
    airport: { label: "Airport Transfer", price: 10 },
    effort: { label: "Extra Effort / Luggage", price: 10 },
    city: { label: "City Service", price: 10 },
    private_cruise: { label: "Private Cruise", price: 30 },
    night: { label: "Night Service (22:00–06:00)", price: 10 },
  };

  let faresData = null;

  function getFareKey(selected) {
    if (!selected || selected.length === 0) return "base";
    return selected.slice().sort().join(",");
  }

  function getTotal(selected) {
    if (!faresData) return null;
    const key = getFareKey(selected);
    return faresData[key] ? faresData[key].total : null;
  }

  function getBreakdown(selected) {
    if (!faresData) return null;
    const key = getFareKey(selected);
    return faresData[key] ? faresData[key].breakdown : null;
  }

  function renderWidget(container, preselect) {
    container.innerHTML = `
      <div class="fare-calculator">
        <h3 class="fare-title">Estimate Your Fare</h3>
        <p class="fare-subtitle">Select the services that apply to your journey:</p>
        <div class="fare-options">
          ${Object.entries(SURCHARGE_LABELS)
            .map(
              ([key, info]) => `
            <label class="fare-option">
              <input type="checkbox" name="surcharge" value="${key}"
                ${preselect.includes(key) ? "checked" : ""}>
              <span class="fare-option-label">${info.label}</span>
              <span class="fare-option-price">+€${info.price}</span>
            </label>`
            )
            .join("")}
        </div>
        <div class="fare-result">
          <div class="fare-breakdown" id="fare-breakdown-${container.id}"></div>
          <div class="fare-total">
            <span class="fare-total-label">Estimated Total</span>
            <span class="fare-total-amount" id="fare-total-${container.id}">€15</span>
          </div>
        </div>
        <p class="fare-note">* Final fare confirmed at booking. Night service applies between 22:00–06:00.</p>
      </div>`;

    container.querySelectorAll('input[name="surcharge"]').forEach((cb) => {
      cb.addEventListener("change", () => updateDisplay(container));
    });

    updateDisplay(container);
  }

  function updateDisplay(container) {
    const checked = Array.from(
      container.querySelectorAll('input[name="surcharge"]:checked')
    ).map((cb) => cb.value);

    const total = getTotal(checked);
    const breakdown = getBreakdown(checked);

    const totalEl = container.querySelector('[id^="fare-total-"]');
    const breakdownEl = container.querySelector('[id^="fare-breakdown-"]');

    if (total !== null) {
      totalEl.textContent = `€${total}`;

      const lines = Object.entries(breakdown).map(([k, v]) => {
        const label =
          k === "base"
            ? "Base fare"
            : SURCHARGE_LABELS[k]
            ? SURCHARGE_LABELS[k].label
            : k;
        return `<div class="fare-line"><span>${label}</span><span>€${v}</span></div>`;
      });
      breakdownEl.innerHTML = lines.join("");
    }
  }

  window.initFareCalculator = function (options) {
    const opts = options || {};
    const preselect = opts.preselect || [];
    const containerId = opts.containerId || "fare-calculator";

    const container = document.getElementById(containerId);
    if (!container) {
      console.warn("Fare calculator container not found:", containerId);
      return;
    }

    fetch("/assets/data/fares.json")
      .then((r) => r.json())
      .then((data) => {
        faresData = data;
        renderWidget(container, preselect);
      })
      .catch((err) => {
        console.error("Failed to load fares data:", err);
        container.innerHTML =
          '<p class="fare-error">Fare calculator unavailable. Please contact us for a quote.</p>';
      });
  };
})();
